/* ═══════════════════════════════════════════════════════════════════════════
   AURA ALPHA — Getting Started
   4-path onboarding with progress checklist and achievement badges.
   Routes new users to the right experience based on their intent.
   ═══════════════════════════════════════════════════════════════════════════ */
import { useState, useEffect, useCallback } from 'react';
import { useNavigate } from 'react-router-dom';
import { motion } from 'framer-motion';
import AnimatedPage from '../components/AnimatedPage';
import usePageTitle from '../hooks/usePageTitle';
import useIsMobile from '../hooks/useIsMobile';
import { api } from '../utils/api';
import { tokens } from '../styles/tokens';
import GlassPanel from '../components/ui/GlassPanel';
import s from './GettingStartedPage.module.css';

const C = {
  bg: tokens.color.bg, surface: tokens.color.surface, surface2: tokens.color.surfaceHover,
  border: tokens.color.border, textPrimary: tokens.color.text, textSecondary: tokens.color.textSecondary,
  green: tokens.color.green, red: tokens.color.red, blue: tokens.color.blue,
  amber: tokens.color.amber, purple: tokens.color.purple, cyan: tokens.color.cyan,
};
const mono = tokens.font.mono;
const body = tokens.font.sans;

// ── Progress persistence ────────────────────────────────────────────────
const PROGRESS_KEY = 'aura_getting_started_progress';
const BADGES_KEY = 'aura_getting_started_badges';

function loadProgress() {
  try { return JSON.parse(localStorage.getItem(PROGRESS_KEY) || '{}'); } catch { return {}; }
}
function saveProgress(p) {
  localStorage.setItem(PROGRESS_KEY, JSON.stringify(p));
}
function loadBadges() {
  try { return JSON.parse(localStorage.getItem(BADGES_KEY) || '[]'); } catch { return []; }
}
function saveBadges(b) {
  localStorage.setItem(BADGES_KEY, JSON.stringify(b));
}

// ── Path cards ──────────────────────────────────────────────────────────
const PATHS = [
  {
    key: 'paper',
    title: 'Paper Trade',
    subtitle: 'Zero risk, real strategies',
    desc: 'Practice with $100K in simulated money. See how our strategies perform before putting real capital to work.',
    icon: 'SIM',
    color: C.green,
    dimColor: 'rgba(34,197,94,0.12)',
    borderColor: 'rgba(34,197,94,0.25)',
    route: '/paper-trading',
    badge: 'Paper Pioneer',
  },
  {
    key: 'live',
    title: 'Live Trading',
    subtitle: 'Connect your broker',
    desc: 'Set up IBKR Gateway connection and start trading with real capital. Our bots handle execution while you stay in control.',
    icon: 'LIVE',
    color: C.blue,
    dimColor: 'rgba(96,165,250,0.12)',
    borderColor: 'rgba(96,165,250,0.25)',
    route: '/brokers',
    badge: 'Going Live',
  },
  {
    key: 'signals',
    title: 'Signal Alerts',
    subtitle: 'Get notified of top signals',
    desc: 'Set up push notifications for the highest-confidence trading signals. No broker needed -- just alerts to your phone.',
    icon: 'BELL',
    color: C.amber,
    dimColor: 'rgba(245,158,11,0.12)',
    borderColor: 'rgba(245,158,11,0.25)',
    route: '/notifications',
    badge: 'Signal Seeker',
  },
  {
    key: 'explore',
    title: 'Just Explore',
    subtitle: 'Browse the platform',
    desc: 'Take a self-guided tour of strategies, scanners, backtests, and analytics. No commitment, just curiosity.',
    icon: 'EYE',
    color: C.purple,
    dimColor: 'rgba(167,139,250,0.12)',
    borderColor: 'rgba(167,139,250,0.25)',
    route: '/home',
    badge: 'Explorer',
  },
];

// ── Checklist items ─────────────────────────────────────────────────────
const CHECKLIST = [
  { key: 'account_created', label: 'Account created', auto: true },
  { key: 'path_chosen', label: 'Choose your path' },
  { key: 'first_strategy', label: 'Set up first strategy' },
  { key: 'first_signal', label: 'Review first signal' },
];

// ── Path Icon SVGs ──────────────────────────────────────────────────────
function PathIcon({ type, color }) {
  const size = 32;
  const style = { fontFamily: mono, fontSize: 14, fontWeight: 800, color };

  if (type === 'SIM') return (
    <div style={{ width: size, height: size, display: 'flex', alignItems: 'center', justifyContent: 'center', ...style }}>
      <svg width={size} height={size} viewBox="0 0 32 32" fill="none">
        <rect x="4" y="6" width="24" height="20" rx="3" stroke="currentColor" strokeWidth="2" fill="none" />
        <path d="M10 16h12M16 12v8" stroke="currentColor" strokeWidth="2" strokeLinecap="round" />
      </svg>
    </div>
  );

  if (type === 'LIVE') return (
    <div style={{ width: size, height: size, display: 'flex', alignItems: 'center', justifyContent: 'center', ...style }}>
      <svg width={size} height={size} viewBox="0 0 32 32" fill="none">
        <circle cx="16" cy="16" r="10" stroke="currentColor" strokeWidth="2" fill="none" />
        <circle cx="16" cy="16" r="4" fill="currentColor" />
        <path d="M16 6v2M16 24v2M6 16h2M24 16h2" stroke="currentColor" strokeWidth="2" strokeLinecap="round" />
      </svg>
    </div>
  );

  if (type === 'BELL') return (
    <div style={{ width: size, height: size, display: 'flex', alignItems: 'center', justifyContent: 'center', ...style }}>
      <svg width={size} height={size} viewBox="0 0 32 32" fill="none">
        <path d="M16 4c-4.4 0-8 3.6-8 8v6l-2 3h20l-2-3v-6c0-4.4-3.6-8-8-8z" stroke="currentColor" strokeWidth="2" fill="none" />
        <path d="M13 25c0 1.7 1.3 3 3 3s3-1.3 3-3" stroke="currentColor" strokeWidth="2" strokeLinecap="round" />
      </svg>
    </div>
  );

  // EYE
  return (
    <div style={{ width: size, height: size, display: 'flex', alignItems: 'center', justifyContent: 'center', ...style }}>
      <svg width={size} height={size} viewBox="0 0 32 32" fill="none">
        <path d="M3 16s5-8 13-8 13 8 13 8-5 8-13 8S3 16 3 16z" stroke="currentColor" strokeWidth="2" fill="none" />
        <circle cx="16" cy="16" r="4" stroke="currentColor" strokeWidth="2" fill="none" />
      </svg>
    </div>
  );
}

// ═════════════════════════════════════════════════════════════════════════
// MAIN COMPONENT
// ═════════════════════════════════════════════════════════════════════════
export default function GettingStartedPage() {
  usePageTitle('Getting Started');
  const isMobile = useIsMobile();
  const navigate = useNavigate();

  const [progress, setProgress] = useState(() => loadProgress());
  const [badges, setBadges] = useState(() => loadBadges());
  const [hoveredPath, setHoveredPath] = useState(null);

  // Auto-check "account created" on mount
  useEffect(() => {
    const token = localStorage.getItem('aura_token');
    if (token && !progress.account_created) {
      const next = { ...progress, account_created: true };
      setProgress(next);
      saveProgress(next);
    }
  }, []); // eslint-disable-line react-hooks/exhaustive-deps

  // Check progress from API signals/strategies
  useEffect(() => {
    const ac = new AbortController();

    // Check if user has reviewed a signal
    api('/scanners/signals/live?limit=1', { signal: ac.signal, silent: true })
      .then(data => {
        if (data?.signals?.length > 0 && !progress.first_signal) {
          // If there are signals, mark as available (not yet "reviewed" — that happens on click)
        }
      });

    return () => ac.abort();
  }, []); // eslint-disable-line react-hooks/exhaustive-deps

  const markStep = useCallback((key) => {
    setProgress(prev => {
      if (prev[key]) return prev;
      const next = { ...prev, [key]: true };
      saveProgress(next);
      return next;
    });
  }, []);

  const earnBadge = useCallback((badge) => {
    setBadges(prev => {
      if (prev.includes(badge)) return prev;
      const next = [...prev, badge];
      saveBadges(next);
      return next;
    });
  }, []);

  const handlePathClick = useCallback((path) => {
    markStep('path_chosen');
    earnBadge(path.badge);

    // Mark strategy step for paper/live paths
    if (path.key === 'paper' || path.key === 'live') {
      markStep('first_strategy');
    }
    if (path.key === 'signals') {
      markStep('first_signal');
    }

    navigate(path.route);
  }, [markStep, earnBadge, navigate]);

  const completedSteps = CHECKLIST.filter(c => progress[c.key]).length;
  const totalSteps = CHECKLIST.length;

  return (
    <AnimatedPage>
      <div className={s.root} style={{ padding: isMobile ? 12 : 20 }}>

        {/* ── Header ──────────────────────────────────────────────── */}
        <div style={{ textAlign: 'center', marginBottom: 32 }}>
          <h1 style={{
            fontFamily: body, fontSize: isMobile ? 24 : 32, fontWeight: 800,
            color: C.textPrimary, margin: 0, marginBottom: 8,
          }}>
            Welcome to Aura Alpha
          </h1>
          <p style={{
            fontFamily: body, fontSize: 15, color: C.textSecondary, margin: 0, maxWidth: 520,
            marginLeft: 'auto', marginRight: 'auto', lineHeight: 1.5,
          }}>
            Choose how you want to start. You can always switch later.
          </p>
        </div>

        {/* ── 4 Path Cards ───────────────────────────────────────── */}
        <div style={{
          display: 'grid',
          gridTemplateColumns: isMobile ? '1fr' : 'repeat(2, 1fr)',
          gap: 16, maxWidth: 800, margin: '0 auto 32px',
        }}>
          {PATHS.map((path) => (
            <motion.button
              key={path.key}
              whileHover={{ scale: 1.02, y: -2 }}
              whileTap={{ scale: 0.98 }}
              onHoverStart={() => setHoveredPath(path.key)}
              onHoverEnd={() => setHoveredPath(null)}
              onClick={() => handlePathClick(path)}
              className={s.pathCard}
              style={{
                background: hoveredPath === path.key ? path.dimColor : C.surface,
                border: `1px solid ${hoveredPath === path.key ? path.borderColor : C.border}`,
                borderRadius: 14, padding: isMobile ? 20 : 24, cursor: 'pointer',
                textAlign: 'left', transition: 'all 0.2s ease',
                display: 'flex', flexDirection: 'column', gap: 12,
              }}
            >
              {/* Icon + Title row */}
              <div style={{ display: 'flex', alignItems: 'center', gap: 12 }}>
                <div style={{
                  width: 48, height: 48, borderRadius: 12,
                  display: 'flex', alignItems: 'center', justifyContent: 'center',
                  background: path.dimColor, color: path.color,
                }}>
                  <PathIcon type={path.icon} color={path.color} />
                </div>
                <div>
                  <div style={{ fontFamily: body, fontSize: 16, fontWeight: 700, color: C.textPrimary }}>
                    {path.title}
                  </div>
                  <div style={{ fontFamily: mono, fontSize: 11, fontWeight: 600, color: path.color }}>
                    {path.subtitle}
                  </div>
                </div>
              </div>

              {/* Description */}
              <div style={{ fontFamily: body, fontSize: 13, color: C.textSecondary, lineHeight: 1.5 }}>
                {path.desc}
              </div>

              {/* CTA arrow */}
              <div style={{
                fontFamily: mono, fontSize: 12, fontWeight: 700, color: path.color,
                display: 'flex', alignItems: 'center', gap: 4,
              }}>
                Get Started
                <span style={{ fontSize: 14 }}>&rarr;</span>
              </div>
            </motion.button>
          ))}
        </div>

        {/* ── Progress Checklist ──────────────────────────────────── */}
        <div style={{ maxWidth: 480, margin: '0 auto 32px' }}>
          <GlassPanel padding={isMobile ? 16 : 24}>
            <div style={{
              display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 16,
            }}>
              <span style={{
                fontFamily: mono, fontSize: 10, fontWeight: 700,
                color: C.textSecondary, textTransform: 'uppercase', letterSpacing: '0.08em',
              }}>
                Your Progress
              </span>
              <span style={{
                fontFamily: mono, fontSize: 12, fontWeight: 700,
                color: completedSteps === totalSteps ? C.green : C.blue,
              }}>
                {completedSteps}/{totalSteps}
              </span>
            </div>

            {/* Progress bar */}
            <div style={{
              height: 6, borderRadius: 3, background: 'rgba(255,255,255,0.06)',
              marginBottom: 16, overflow: 'hidden',
            }}>
              <motion.div
                initial={{ width: 0 }}
                animate={{ width: `${(completedSteps / totalSteps) * 100}%` }}
                transition={{ duration: 0.5, ease: 'easeOut' }}
                style={{
                  height: '100%', borderRadius: 3,
                  background: completedSteps === totalSteps
                    ? C.green
                    : `linear-gradient(90deg, ${C.blue.replace('var(--color-blue, ', '').replace(')', '')} 0%, ${C.purple.replace('var(--color-purple, ', '').replace(')', '')} 100%)`,
                }}
              />
            </div>

            {/* Checklist items */}
            <div style={{ display: 'flex', flexDirection: 'column', gap: 10 }}>
              {CHECKLIST.map(item => {
                const done = !!progress[item.key];
                return (
                  <div key={item.key} style={{
                    display: 'flex', alignItems: 'center', gap: 10,
                  }}>
                    <div style={{
                      width: 22, height: 22, borderRadius: 6,
                      display: 'flex', alignItems: 'center', justifyContent: 'center',
                      border: `2px solid ${done ? C.green : C.border}`,
                      background: done ? 'rgba(34,197,94,0.12)' : 'transparent',
                      fontFamily: mono, fontSize: 11, fontWeight: 800,
                      color: done ? C.green : C.textSecondary,
                      transition: 'all 0.2s ease',
                    }}>
                      {done ? '\u2713' : ''}
                    </div>
                    <span style={{
                      fontFamily: body, fontSize: 13, fontWeight: done ? 600 : 400,
                      color: done ? C.textPrimary : C.textSecondary,
                      textDecoration: done ? 'none' : 'none',
                    }}>
                      {item.label}
                    </span>
                  </div>
                );
              })}
            </div>
          </GlassPanel>
        </div>

        {/* ── Badges Earned ──────────────────────────────────────── */}
        {badges.length > 0 && (
          <div style={{ maxWidth: 480, margin: '0 auto' }}>
            <GlassPanel padding={isMobile ? 16 : 24}>
              <div style={{
                fontFamily: mono, fontSize: 10, fontWeight: 700,
                color: C.textSecondary, textTransform: 'uppercase', letterSpacing: '0.08em',
                marginBottom: 12,
              }}>
                Badges Earned
              </div>
              <div style={{ display: 'flex', gap: 8, flexWrap: 'wrap' }}>
                {badges.map(badge => (
                  <motion.div
                    key={badge}
                    initial={{ scale: 0 }}
                    animate={{ scale: 1 }}
                    style={{
                      fontFamily: mono, fontSize: 11, fontWeight: 700,
                      padding: '6px 14px', borderRadius: 14,
                      background: 'rgba(96,165,250,0.12)',
                      color: C.blue,
                      border: '1px solid rgba(96,165,250,0.2)',
                    }}
                  >
                    {badge}
                  </motion.div>
                ))}
              </div>
            </GlassPanel>
          </div>
        )}
      </div>
    </AnimatedPage>
  );
}
